// ======================== NAMED EXPORTS FOR LOOKUPS ========================
const ITEM_IDS = {};
ALL_ITEMS.forEach(item => {
  const key = item.name.normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-zA-Z0-9]/g, '_').toUpperCase();
  ITEM_IDS[key] = item.id;
});

